const express = require('express');
const http = require('http');
const { v4: uuidv4 } = require('uuid');
const socketIO = require('socket.io');

// initialize express server and http server
const app = express();
const server = http.createServer(app);

// initialize socket.io with the http server
const io = socketIO(server);

let players = {}; // key: UUID, value: username

// socket.io events
io.on('connection', (socket) => {
    console.log("New client connected");
  
    // handle player login
    socket.on('login', (username) => {
        const id = uuidv4();
      
        players[id] = username;
      
        socket.playerId = id;
        
        console.log(`User ${username} connected with UUID: ${socket.playerId}`);
    });
  
    // handle score update from client
    socket.on('updateScore', (score) => {
      if (!players[socket.playerId]) return;
      
        console.log(`Player with ID ${socket.playerId} updated their score to: ${score}`);
        
        // TODO: Implement actual game logic and validation
    });
  
    socket.on('disconnect', () => {
      if (!players[socket.playerId]) return;
      
        console.log(`Player with ID ${socket.playerId} disconnected`);
        
        delete players[socket.playerId]; // remove player from list of connected users
    });
});
  
// start server
const port = process.env.PORT || 4001;
server.listen(port, () => console.log("Server listening on port " + port));